const results = [];

let currentSLNo = null;
let currentClause = null;
let currentSection = null;

for (const item of items) {
  const row = item.json;

  const descRaw = row.Description || "";
  const desc = descRaw.replace(/\s+/g, " ").trim();

  const slNo = row["SL.No"] ?? null;
  const clause = row["Clause No"] ?? null;

  if (!desc) continue;

  // Update SL.No
  if (slNo !== null && slNo !== undefined) {
    currentSLNo = slNo;
  }

  // Clause change ⇒ reset section
  if (clause && clause !== currentClause) {
    currentClause = clause;
    currentSection = null;
  }

  // Detect section headers
  const isSectionHeader =
    desc.endsWith(":-") ||
    desc.endsWith(":") ||
    desc.toLowerCase().includes("conditions") ||
    desc.toLowerCase().includes("insulation levels") ||
    desc.toLowerCase().includes("tap changing") ||
    desc.toLowerCase().includes("cooling equipments") ||
    desc === desc.toUpperCase();

  if (isSectionHeader) {
    currentSection = desc;
    continue;
  }

  results.push({
    sl_no: currentSLNo,
    clause_no: currentClause || "",
    section: currentSection || "",
    parameter_name: desc
  });
}

return results.map(r => ({ json: r }));

