// Extract current row
const slNo = $json["sl_no"] ?? null;
const clause = $json["clause_no"] ?? "";
const section = $json["section"] ?? "";
const parameter_name = ($json["parameter_name"] || "").trim();

// Build a STRICT, JSON-enforced question
const question = `
You are extracting information from a tender document.

TASK:
Extract the value for the technical parameter below.

PARAMETER:
"${parameter_name}"

${section ? `SECTION: ${section}` : ""}
${clause ? `CLAUSE REFERENCE: ${clause}` : ""}

RULES (MANDATORY):
- Use ONLY the provided context
- Do NOT add explanations or commentary
- Do NOT include extra fields
- If the value is descriptive (e.g. Scope), return the relevant text
- If the value is not found, return null
- Identify the page number where the value appears

OUTPUT FORMAT (STRICT JSON ONLY):
{
  "sl_no": ${slNo},
  "parameter": "${parameter_name}",
  "value": "... or null",
  "page": "... or null"
}

IMPORTANT:
- Return ONLY valid JSON
- Do NOT wrap the response in markdown
- Do NOT add any text before or after the JSON
`.trim();

// Output
return [
  {
    json: {
      sl_no: slNo,
      parameter_name,
      clause,
      section,
      question
    }
  }
];

// The Q&A Chain returns JSON as a STRING inside `response`
let parsed;

try {
  parsed = JSON.parse($json.response);
} catch (e) {
  // Safety fallback if parsing fails
  parsed = {
    sl_no: $json.sl_no ?? null,
    parameter: $json.parameter ?? null,
    value: null,
    page: null
  };
}

return [
  {
    json: {
      sl_no: parsed.sl_no,
      parameter: parsed.parameter,
      value: parsed.value,
      page: parsed.page
    }
  }
];

const text = $json.raw_text;

const normalized = text
  .replace(/\r/g, "")
  .replace(/[ \t]+/g, " ")
  .replace(/\n{3,}/g, "\n\n")
  .trim();

return [{
  json: {
    normalized_text: normalized
  }
}];

const pages = $json.normalized_text.split("\f");

return pages
  .map((content, index) => ({
    json: {
      page_no: index + 1,
      text: content.trim()
    }
  }))
  .filter(p => p.json.text.length > 0);

return items.map(item => {
  const text = item.json.text.toLowerCase();

  return {
    json: {
      ...item.json,
      word_count: text.split(/\s+/).length,
      has_table_like_content: /\|/.test(text) || text.includes("schedule"),
      has_section_keyword: /section|part|volume|annexure/.test(text)
    }
  };
});

  // const text = item.json.text.toLowerCase();

  // return {
  //   json: {
  //     ...item.json,
  //     word_count: text.split(/\s+/).length,
  //     has_table_like_content: /\|/.test(text) || text.includes("schedule"),
  //     has_section_keyword: /section|part|volume|annexure/.test(text)
  //   }
  // };

return items.map(item => {
  const t = (item.json.text || "").toLowerCase();
  let section = "UNKNOWN";

  if (t.includes("invitation for bids")) section = "IFB";
  else if (t.includes("instructions to bidders")) section = "ITB";
  else if (t.includes("bid data sheet")) section = "BDS";
  else if (t.includes("evaluation and qualification")) section = "EVALUATION";
  else if (t.includes("technical specification")) section = "TECH_SPEC";
  else if (t.includes("schedule of requirements")) section = "SOR";
  else if (t.includes("general conditions")) section = "GCC";
  else if (t.includes("particular conditions")) section = "PCC";
  else if (t.includes("annexure")) section = "ANNEXURE";
  else if (t.includes("price") && t.includes("bid")) section = "PRICE";

  return {
    json: {
      ...item.json,
      snippet: item.json.text.slice(0, 700),
      heuristic_section: section
    }
  };
});

// Step 1: sort by page number
const pages = items
  .map(i => i.json)
  .sort((a, b) => a.page_no - b.page_no);

const sections = [];
let current = null;

for (const p of pages) {
  const section = p.heuristic_section || "UNKNOWN";

  if (!current) {
    current = {
      section,
      start_page: p.page_no,
      end_page: p.page_no,
      pages: [p.page_no],
      snippets:[{"page_no": p.page_no, "snippet": p.snippet}],
      page_count: 1,
      unknown_pages: section === "UNKNOWN" ? 1 : 0
    };
    continue;
  }

  const isConsecutive = p.page_no === current.end_page + 1;
  const sameSection = section === current.section;

  if (isConsecutive && (sameSection || section === "UNKNOWN")) {
    // merge UNKNOWN into current
    current.end_page = p.page_no;
    current.pages.push(p.page_no);
    current.snippets.push({"page_no": p.page_no, "snippet": p.snippet})
    current.page_count++;
    if (section === "UNKNOWN") current.unknown_pages++;
  } else {
    sections.push(current);
    current = {
      section,
      start_page: p.page_no,
      end_page: p.page_no,
      pages: [p.page_no],
      snippets: [{"page_no": p.page_no, "snippet": p.snippet}],
      page_count: 1,
      unknown_pages: section === "UNKNOWN" ? 1 : 0
    };
  }
}

if (current) sections.push(current);

// Step 2: confidence score
sections.forEach(s => {
  s.confidence = Math.round(
    ((s.page_count - s.unknown_pages) / s.page_count) * 100
  ) / 100;
});

return sections.map(s => ({ json: s }));

const snippets = $json.snippets || [];

const start = snippets[0]?.snippet || "";
const middle = snippets[Math.floor(snippets.length / 2)]?.snippet || "";
const end = snippets[snippets.length - 1]?.snippet || "";

return {
  json: {
    heuristic_section: $json.section,
    page_range: `${$json.start_page}-${$json.end_page}`,
    snippets: {
      start,
      middle,
      end
    },
    page_count: $json.page_count,
    unknown_pages: $json.unknown_pages,
    confidence: $json.confidence

  }
};

return {
  json: {
    // original heuristic fields
    heuristic_section: $json.heuristic_section,
    heuristic_confidence: $json.confidence,
    page_range: $json.page_range,
    snippets: $json.snippets,

    // keep everything else if needed
    _base: $json
  }
};

const base = $("If").first().json
return {
  json: {
    heuristic_section: base.heuristic_section,
    confidence: base.heuristic_confidence,
    page_range: base.page_range,
    snippets: base.snippets,

    final_section: $json.final_section,
    is_correct: $json.is_correct,
    reason: $json.reason,
    confidence_1: $json.confidence
  }
};

const raw = $json.content || "";

// Extract JSON inside ``` if present
const match = raw.match(/\{[\s\S]*\}/);

if (!match) {
  throw new Error("No JSON object found in LLM response");
}

let parsed;
try {
  parsed = JSON.parse(match[0]);
} catch (e) {
  throw new Error("Invalid JSON from LLM");
}

return {
  json: parsed
};

const heuristicConfidence = $json.confidence ?? 0;
const llmConfidence = $json.confidence_1 ?? 0;

let finalConfidence;
let source;

if ($json.is_correct === true) {
  finalConfidence = llmConfidence;
  source = "LLM_CONFIRMED";
} else {
  finalConfidence = Math.max(heuristicConfidence, llmConfidence * 0.7);
  source = "LLM_OVERRULED";
}

return {
  json: {
    ...$json,
    final_confidence: Number(finalConfidence.toFixed(2)),
    final_section: $json.final_section ? $json.final_section : $json.heuristic_section,
    classification_source: source
  }
};

// const base = $("Normalize Section Confidence").all()
// return base

const sectionOrder = [
  "IFB",
  "ITB",
  "BDS",
  "EVALUATION",
  "TECH_SPEC",
  "SOR",
  "PRICE",
  "GCC",
  "PCC",
  "ANNEXURE"
];

const items = $items();
const issues = [];

let lastIndex = -1;

items.forEach((item, idx) => {
  const sec = item.json.final_section;
  const index = sectionOrder.indexOf(sec);

  if (index !== -1 && index < lastIndex) {
    issues.push({
      page_range: item.json.page_range,
      section: sec,
      issue: "SECTION_ORDER_VIOLATION"
    });
  }

  lastIndex = Math.max(lastIndex, index);
});

return {
    json: {
      validated_sections: items.map(i => i.json),
      validation_issues: issues
    }
  }

const sections = $json.validated_sections;

const merged = [];
let current = null;

for (const s of sections) {
  if (
    current &&
    current.final_section === s.final_section &&
    Number(current.page_range.split("-")[1]) + 1 === Number(s.page_range.split("-")[0])
  ) {
    // merge
    current.page_range =
      current.page_range.split("-")[0] + "-" + s.page_range.split("-")[1];
    current.snippets.end = s.snippets.end;
    current.final_confidence = Math.min(
      current.final_confidence,
      s.final_confidence
    );
  } else {
    if (current) merged.push(current);
    current = { ...s };
  }
}

if (current) merged.push(current);

return merged.map(m => ({ json: m }));

let score = 100;

if ($json.final_confidence < 0.6) score -= 25;
if ($json.snippets.middle?.length < 200) score -= 15;
if ($json.heuristic_section === "UNKNOWN") score -= 20;

return {
  json: {
    ...$json,
    section_quality_score: Math.max(score, 0)
  }
};

const sections = $items().map(i => i.json);

return [
  {
    json: {
      tender_id: "TR-36/2024",
      sections_index: sections.map(s => ({
        section: s.final_section,
        pages: s.page_range,
        confidence: s.final_confidence,
        quality_score: s.section_quality_score
      })),
      extracted_at: new Date().toISOString()
    }
  }
];

// Input: Your original tender data (items[0].json)
const tenderData = $input.first().json;  // {tender_id: "...", sections_index: [...]}

const rows = tenderData.sections_index.map(section => ({
  section: section.section,
  pages: section.pages,
  confidence: section.confidence,
  quality_score: section.quality_score
  // Optional: tender_id: tenderData.tender_id
}));

return rows.map(row => ({ json: row }));
